/// <reference path="../../index.d.ts" />
import type { PublicLitElement as LitElement } from "@arcgis/lumina";

/**
 * @cssproperty [--calcite-tab-content-space-y] - Specifies the vertical space between the component's content in the `default` slot.
 * @cssproperty [--calcite-tab-content-block-padding] - [Deprecated] Use `--calcite-tab-content-space-y` instead. Specifies the block padding of the component's content in the `default` slot.
 * @slot  - A slot for adding custom content.
 */
export abstract class Tab extends LitElement {
  /**
   * When `true`, the component is selected.
   *
   * Only one tab can be selected within the `calcite-tabs` parent.
   *
   * @default false
   */
  accessor selected: boolean;
  /**
   * Specifies a unique name for the component.
   *
   * When specified, use the same value on the `calcite-tab-title`.
   */
  accessor tab: string;
  /** Returns the index of the component item within the tab array. */
  getTabIndex(): Promise<number>;
}